package com.pdp.mysql.project;
import com.pdp.project.domain.Project; import com.pdp.project.port.*; import com.pdp.shared.concurrency.*; import java.util.*; import org.springframework.stereotype.Repository;
@Repository public final class MysqlProjectRepository implements ProjectRepository, ProjectHierarchyQuery { private final ProjectMapper mapper; public MysqlProjectRepository(ProjectMapper mapper){this.mapper=mapper;} public Optional<Project> findById(UUID w,UUID id){return Optional.ofNullable(mapper.findById(w,id)).map(ProjectRow::domain);} public Optional<Project> findByProjectNo(UUID w,String n){return Optional.ofNullable(mapper.findByProjectNo(w,n)).map(ProjectRow::domain);} public List<Project> findChildren(UUID w,UUID p){return mapper.findChildren(w,p).stream().map(ProjectRow::domain).toList();} public Project insert(Project p){mapper.insert(ProjectRow.from(p));return p;} public Project update(Project p,Revision expected){if(mapper.update(ProjectRow.from(p))==0)throw new ConcurrencyConflictException(expected,expected);return p;} public boolean wouldCreateCycle(UUID w,UUID p,UUID parent){return p.equals(parent)||mapper.findAncestors(w,parent).contains(p);} public List<UUID> findAncestorIds(UUID w,UUID p){return mapper.findAncestors(w,p);} }
